Function createMultiplier(double factor) {
  return (double value) {
    return value * factor;
  };
}

void main() {
  var half = createMultiplier(0.5);
  var double = createMultiplier(2.0);

  print(half(100));  // 50.0
  print(double(25)); // 50.0

  // Closure as callback with state
  Function makeFilter(int min) {
    return (String item) => item.length >= min;
  }

  var filterShort = makeFilter(5);
  var words = ['cat', 'elephant', 'dog', 'giraffe'];
  print(words.where(filterShort).toList());
}
